#include<bits/stdc++.h>
using namespace std;
int n,m;
double a[100010];
struct node
{
    double max1;
    int len;
}t[400010];
void pushup1(int x)
{
    t[x].max1=max(t[x<<1].max1,t[x<<1|1].max1);
}
double pushup2(double lx,int x,int l,int r)
{
    if(t[x].max1<=lx)
    {
        return 0;
    }
    if(a[l]>lx)
    {
        return t[x].len;
    }
    if(l==r)
    {
        return a[l]>lx;
    }
    int ls=(x<<1),rs=(x<<1|1);
    int mid=(l+r)>>1;
    if(t[ls].max1<=lx)
    {
        return pushup2(lx,rs,mid+1,r);
    }
    else
    {
        return pushup2(lx,ls,l,mid)+t[x].len-t[ls].len;
    }
}
void update(int x,int l,int r,int p,int val)
{
    if(l==r&&l==p)
    {
        t[x].max1=1.0*val/p;
        t[x].len=1;
        return;
    }
    int mid=(l+r)>>1;
    if(p<=mid)
    {
        update(x<<1,l,mid,p,val);
    }
    else if(p>mid)
    {
        update(x<<1|1,mid+1,r,p,val);
    }
    pushup1(x);
    t[x].len=t[x<<1].len+pushup2(t[x<<1].max1,x<<1|1,mid+1,r);
}
int main()
{
    scanf("%d%d",&n,&m);
    for(int i=1;i<=m;i++)
    {
        int x,y;
        scanf("%d%d",&x,&y);
        a[x]=1.0*y/x;
        update(1,1,n,x,y);
        printf("%d\n",t[1].len);
    }
    return 0;
}
